#include <iostream>
using namespace std;

long factorialRecursive(int n)
{
    if (n <= 1) return 1;
    return n * factorialRecursive(n - 1);
}

long factorialIterative(int n)
{
    long result = 1;
    for (int i = 2; i <= n; i++)
    {
        result *= i;
    }
    return result;
}

int main()
{
    cout << "Faktoriyel tablosu (0-10):" << endl;
    for (int i = 0; i <= 10; i++)
    {
        cout << i << "! = " << factorialIterative(i) << endl;
    }

    cout << "\nRecursive 5! = " << factorialRecursive(5) << endl;
    cout << "Iteratif 5! = " << factorialIterative(5) << endl;

    // Kombinasyon hesaplama: C(n,r) = n! / (r! * (n-r)!)
    int n = 5, r = 2;
    long combination = factorialIterative(n) / (factorialIterative(r) * factorialIterative(n - r));
    cout << "\nC(" << n << "," << r << ") = " << combination << endl;

    return 0;
}
